INSERT INTO action_outcome_retrieval_quality_labels (query_id, candidate_id, quality_label, reason) VALUES ('aoe_checkout_002', 'aoe_checkout_001', 'useful', 'Same deploy-linked checkout timeout family; rollback success is a useful contrast to failed restart.');
INSERT INTO action_outcome_retrieval_quality_labels (query_id, candidate_id, quality_label, reason) VALUES ('aoe_checkout_002', 'aoe_checkout_003', 'superficial', 'Similar checkout latency but CPU-driven mitigation is not the same client-pool regression.');
INSERT INTO action_outcome_retrieval_quality_labels (query_id, candidate_id, quality_label, reason) VALUES ('aoe_checkout_002', 'aoe_checkout_004', 'useful', 'Pool wait evidence and config revert provide useful direct-remediation evidence.');
INSERT INTO action_outcome_retrieval_quality_labels (query_id, candidate_id, quality_label, reason) VALUES ('aoe_payment_002', 'aoe_payment_001', 'useful', 'External payment gateway timeout was fixed by traffic drain, unlike the failed scale-out.');
INSERT INTO action_outcome_retrieval_quality_labels (query_id, candidate_id, quality_label, reason) VALUES ('aoe_payment_002', 'aoe_payment_003', 'superficial', 'Payment errors are similar, but single-pod skew does not match service-wide gateway timeout.');
INSERT INTO action_outcome_retrieval_quality_labels (query_id, candidate_id, quality_label, reason) VALUES ('aoe_payment_002', 'aoe_payment_004', 'useful', 'Payment timeout with deploy retry regression gives a useful non-scale-out recovery example.');
INSERT INTO action_outcome_retrieval_quality_labels (query_id, candidate_id, quality_label, reason) VALUES ('aoe_payment_002', 'aoe_distractor_payment_001', 'misleading', 'Scale-out succeeded only because CPU was saturated; query CPU is low and traces point external.');
INSERT INTO action_outcome_retrieval_quality_labels (query_id, candidate_id, quality_label, reason) VALUES ('aoe_inventory_002', 'aoe_inventory_001', 'useful', 'DB pool saturation recovered through config revert, a useful contrast to failed scale-out.');
INSERT INTO action_outcome_retrieval_quality_labels (query_id, candidate_id, quality_label, reason) VALUES ('aoe_inventory_002', 'aoe_inventory_003', 'superficial', 'Inventory DB errors are similar, but one-pod skew does not match service-wide DB saturation.');
INSERT INTO action_outcome_retrieval_quality_labels (query_id, candidate_id, quality_label, reason) VALUES ('aoe_inventory_002', 'aoe_inventory_004', 'useful', 'DB saturation from bulk writes is a useful non-scale-out remediation pattern.');
INSERT INTO action_outcome_retrieval_quality_labels (query_id, candidate_id, quality_label, reason) VALUES ('aoe_inventory_002', 'aoe_distractor_inventory_001', 'misleading', 'Scale-out succeeded only because DB connections were not saturated and app CPU was high.');
INSERT INTO action_outcome_retrieval_quality_labels (query_id, candidate_id, quality_label, reason) VALUES ('aoe_cache_002', 'aoe_cache_001', 'useful', 'Shared recommendation cache freshness lag recovered through targeted cache purge.');
INSERT INTO action_outcome_retrieval_quality_labels (query_id, candidate_id, quality_label, reason) VALUES ('aoe_cache_002', 'aoe_cache_003', 'superficial', 'Recommendation staleness is similar, but deploy fallback regression differs from shared cache lag.');
INSERT INTO action_outcome_retrieval_quality_labels (query_id, candidate_id, quality_label, reason) VALUES ('aoe_cache_002', 'aoe_cache_004', 'useful', 'Failed scale-out is useful negative evidence for shared cache staleness.');
INSERT INTO action_outcome_retrieval_quality_labels (query_id, candidate_id, quality_label, reason) VALUES ('aoe_cache_002', 'aoe_distractor_cache_001', 'misleading', 'Restart worked only for pod-local cache skew, not shared redis freshness lag.');
INSERT INTO action_outcome_retrieval_quality_labels (query_id, candidate_id, quality_label, reason) VALUES ('aoe_cache_002', 'aoe_distractor_cache_002', 'misleading', 'Cache purge failed only because the true root cause was deploy fallback logic.');
INSERT INTO action_outcome_retrieval_quality_labels (query_id, candidate_id, quality_label, reason) VALUES ('aoe_queue_003', 'aoe_queue_001', 'useful', 'Capacity-driven backlog recovered through scale-out, the key contrast to failed restart.');
INSERT INTO action_outcome_retrieval_quality_labels (query_id, candidate_id, quality_label, reason) VALUES ('aoe_queue_003', 'aoe_queue_002', 'superficial', 'Backlog is similar, but poison-message retry loop has a different remediation path.');
INSERT INTO action_outcome_retrieval_quality_labels (query_id, candidate_id, quality_label, reason) VALUES ('aoe_queue_003', 'aoe_queue_004', 'superficial', 'Traffic drain protected checkout during broker throttle but does not solve capacity backlog.');
INSERT INTO action_outcome_retrieval_quality_labels (query_id, candidate_id, quality_label, reason) VALUES ('aoe_queue_003', 'aoe_distractor_queue_001', 'misleading', 'Restart succeeded only for one stuck consumer partition, not broad capacity shortage.');
INSERT INTO action_outcome_retrieval_quality_labels (query_id, candidate_id, quality_label, reason) VALUES ('aoe_queue_003', 'aoe_distractor_queue_002', 'misleading', 'Scale-out failed because of poison-message retries, not because scale-out is wrong for capacity backlog.');
INSERT INTO action_outcome_retrieval_quality_labels (query_id, candidate_id, quality_label, reason) VALUES ('aoe_search_003', 'aoe_search_001', 'superficial', 'Restart mitigates memory pressure but is not durable for deploy-wide search leak.');
INSERT INTO action_outcome_retrieval_quality_labels (query_id, candidate_id, quality_label, reason) VALUES ('aoe_search_003', 'aoe_search_002', 'useful', 'Rollback fixed deploy-correlated monotonic RSS growth, matching the durable action needed.');
INSERT INTO action_outcome_retrieval_quality_labels (query_id, candidate_id, quality_label, reason) VALUES ('aoe_search_003', 'aoe_search_004', 'superficial', 'Shard-local traffic drain is useful mitigation but not the same deploy-wide leak.');
INSERT INTO action_outcome_retrieval_quality_labels (query_id, candidate_id, quality_label, reason) VALUES ('aoe_search_003', 'aoe_distractor_search_001', 'misleading', 'Restart succeeded only for a single-pod leak without deploy correlation.');
INSERT INTO action_outcome_retrieval_quality_labels (query_id, candidate_id, quality_label, reason) VALUES ('aoe_search_003', 'aoe_distractor_search_002', 'misleading', 'Rollback failed because index refresh, not binary deploy, caused the memory spike.');
